import React, { useEffect, useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function AdminDashboard() {
  const [reservations, setReservations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [actionLoading, setActionLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchReservations();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  async function fetchReservations() {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.get(`${API_BASE}/api/reservations/`);
      const data = Array.isArray(res.data) ? res.data : res.data.results || [];
      setReservations(data.sort((a, b) => new Date(b.created_at) - new Date(a.created_at)));
    } catch (err) {
      console.error(err);
      setError("Unable to load dashboard data. Check API and CORS.");
    } finally {
      setLoading(false);
    }
  }

  // quick actions
  async function changeStatus(id, status) {
    setActionLoading(true);
    try {
      await axios.patch(`${API_BASE}/api/reservations/${id}/`, { status });
      setReservations((prev) => prev.map((r) => (r.id === id ? { ...r, status } : r)));
    } catch (err) {
      console.error(err);
      alert("Action failed.");
    } finally {
      setActionLoading(false);
    }
  }

  // stats
  const total = reservations.length;
  const pending = reservations.filter((r) => (r.status || "").toLowerCase() === "pending").length;
  const confirmed = reservations.filter((r) => (r.status || "").toLowerCase() === "confirmed").length;
  const recent = reservations.slice(0, 8);

  function prettyDate(d) {
    if (!d) return "-";
    const dt = new Date(d);
    return isNaN(dt) ? d : dt.toLocaleString();
  }

  return (
    <div>
      <style>{`
        :root{
          --bg-dark:#0b1020;
          --card:#0f1724;
          --muted:#9ca3af;
          --accent:#c89d5c;
          --accent-2:#3b82f6;
          color-scheme: dark;
        }
        *{box-sizing:border-box;font-family:Inter,ui-sans-serif,system-ui,-apple-system,'Segoe UI',Roboto,'Helvetica Neue',Arial;}
        .admin-wrap{min-height:100vh;background:linear-gradient(180deg,#05060a 0%, #071024 100%);padding:28px;}
        .grid{display:grid;gap:16px}
        .cards{grid-template-columns:repeat(4,1fr);display:grid;margin-bottom:18px;gap:14px}
        .card{background:var(--card);padding:18px;border-radius:12px;box-shadow:0 6px 18px rgba(2,6,23,0.6);color:#e6eef8}
        .card h3{margin:0;font-size:13px;color:var(--muted);font-weight:600}
        .card .value{font-size:22px;font-weight:700;margin-top:8px}
        .top-row{display:flex;justify-content:space-between;align-items:center;margin-bottom:18px}
        .title{font-size:20px;color:var(--accent);font-weight:700}
        .muted{color:var(--muted)}
        .table{background:var(--card);border-radius:10px;padding:12px;overflow:auto}
        table{width:100%;border-collapse:collapse;color:#e6eef8}
        th,td{padding:10px 8px;text-align:left;border-bottom:1px solid rgba(255,255,255,0.03);font-size:13px}
        th{color:var(--muted);font-weight:600}
        tr:hover td{background:rgba(255,255,255,0.01)}
        .btn{padding:6px 8px;border-radius:6px;border:none;cursor:pointer;font-size:13px}
        .btn-sm{font-size:12px;padding:6px 8px;border-radius:6px}
        .btn-confirm{background:#16a34a;color:white}
        .btn-cancel{background:#ef4444;color:white}
        .btn-link{background:transparent;color:var(--accent-2);text-decoration:underline;border:0}
        .row-actions{display:flex;gap:8px;align-items:center}
        @media (max-width:900px){
          .cards{grid-template-columns:repeat(2,1fr)}
        }
        @media (max-width:600px){
          .cards{grid-template-columns:1fr}
        }
      `}</style>

      <div className="admin-wrap">
        <div className="top-row">
          <div>
            <div className="title">Admin Dashboard</div>
            <div className="muted" style={{ marginTop: 6 }}>Overview and recent activity</div>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button className="btn btn-sm" onClick={fetchReservations} disabled={loading}>
              {loading ? "Refreshing..." : "Refresh"}
            </button>
            <Link to="/admin/reservations" className="btn btn-link">Open Reservations</Link>
          </div>
        </div>

        <div className="cards">
          <div className="card">
            <h3>Total bookings</h3>
            <div className="value">{total}</div>
            <div className="muted" style={{ marginTop: 8 }}>All received bookings</div>
          </div>

          <div className="card">
            <h3>Pending</h3>
            <div className="value" style={{ color: "#f59e0b" }}>{pending}</div>
            <div className="muted" style={{ marginTop: 8 }}>Awaiting admin confirmation</div>
          </div>

          <div className="card">
            <h3>Confirmed</h3>
            <div className="value" style={{ color: "#34d399" }}>{confirmed}</div>
            <div className="muted" style={{ marginTop: 8 }}>Confirmed bookings</div>
          </div>

          <div className="card">
            <h3>Recent (8)</h3>
            <div className="value">{recent.length}</div>
            <div className="muted" style={{ marginTop: 8 }}>Latest reservations</div>
          </div>
        </div>

        <div className="grid">
          <div className="card">
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
              <div style={{ fontWeight: 700 }}>Recent Reservations</div>
              <div className="muted">Latest first</div>
            </div>

            {error && <div style={{ color: "#f87171", marginBottom: 8 }}>{error}</div>}

            <div className="table">
              <table>
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Guest</th>
                    <th>Check-in</th>
                    <th>Check-out</th>
                    <th>Status</th>
                    <th>Contact</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {recent.length === 0 ? (
                    <tr><td colSpan="7" className="muted">No recent reservations</td></tr>
                  ) : recent.map((r) => (
                    <tr key={r.id}>
                      <td>{r.id}</td>
                      <td style={{ minWidth: 160 }}>
                        <div style={{ fontWeight: 700 }}>{r.name}</div>
                        <div className="muted">{r.room_type || "-"}</div>
                      </td>
                      <td>{r.check_in || "-"}</td>
                      <td>{r.check_out || "-"}</td>
                      <td style={{ fontWeight: 700, color: r.status === "Confirmed" ? "#34d399" : (r.status === "Pending" ? "#f59e0b" : "#ef4444") }}>
                        {r.status || "-"}
                      </td>
                      <td style={{ minWidth: 160 }}>
                        <div className="muted">{r.email || "-"}</div>
                        <div className="muted">{r.phone || "-"}</div>
                      </td>
                      <td>
                        <div className="row-actions">
                          <button className="btn btn-sm" onClick={() => window.location.href = `/admin/reservations?view=${r.id}`}>View</button>
                          {r.status === "Pending" && (
                            <>
                              <button className="btn btn-confirm" onClick={() => changeStatus(r.id, "Confirmed")} disabled={actionLoading}>Confirm</button>
                              <button className="btn btn-cancel" onClick={() => changeStatus(r.id, "Cancelled")} disabled={actionLoading}>Cancel</button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Placeholder card for quick stats or charts */}
          <div className="card">
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ fontWeight: 700 }}>Quick Insights</div>
              <div className="muted">Snapshot</div>
            </div>

            <div style={{ marginTop: 12 }} className="muted">
              <div style={{ marginBottom: 10 }}>
                <div style={{ fontSize: 12 }}>Recent Confirm Ratio</div>
                <div style={{ marginTop: 6, fontWeight: 700 }}>{total === 0 ? "—" : Math.round((confirmed / total) * 100)}%</div>
              </div>

              <div>
                <div style={{ fontSize: 12 }}>Pending to Confirm trend</div>
                <div style={{ marginTop: 10, height: 80, background: "linear-gradient(90deg,#06202a,#071024)", borderRadius: 8, display:"flex",alignItems:"center",justifyContent:"center" }}>
                  <div className="muted">Chart placeholder</div>
                </div>
              </div>
            </div>

            <div style={{ marginTop: 12, display: "flex", gap: 8 }}>
              <button className="btn btn-link" onClick={() => window.location.href = "/admin/reservations"}>Open full list</button>
              <button className="btn btn-sm" onClick={() => { navigator.clipboard?.writeText(JSON.stringify(recent.slice(0, 5), null, 2)); alert("Copied sample JSON"); }}>Copy sample JSON</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
